#!/usr/bin/swift
import Foundation

// ---- Data types (inlined from TimeCalculations.swift) ----

struct ScreenEvent {
    enum Kind: String {
        case on, off, screensaverOn, screensaverOff
        var isAway: Bool { self == .off || self == .screensaverOn }
    }
    let kind: Kind
    let time: Date
}

struct ProjectEntry {
    let project: String
    let time: Date
}

struct TimeSpan {
    let start: Date
    let end: Date?
    let isActive: Bool
}

struct ProjectDuration {
    let project: String
    let duration: TimeInterval
}

enum TimeCalculations {
    static func buildTimeSpans(from events: [ScreenEvent], projectEntries: [ProjectEntry] = [],
                               mergeThreshold: TimeInterval = 3 * 60, now: Date) -> [TimeSpan] {
        var rawSpans: [(start: Date, end: Date)] = []
        var spanStart: Date?
        for event in events {
            switch event.kind {
            case .on, .screensaverOff:
                if spanStart == nil { spanStart = event.time }
            case .off, .screensaverOn:
                if let s = spanStart { rawSpans.append((start: s, end: event.time)); spanStart = nil }
            }
        }
        let activeStart = spanStart

        func gapCoveredByWork(gapEnd: Date) -> Bool {
            guard let first = projectEntries.first(where: { $0.time >= gapEnd }) else { return false }
            return first.project != "Break"
        }

        var merged: [(start: Date, end: Date)] = []
        for span in rawSpans {
            if let last = merged.last {
                let gap = span.start.timeIntervalSince(last.end)
                if gap < mergeThreshold || gapCoveredByWork(gapEnd: span.start) {
                    merged[merged.count - 1] = (start: last.start, end: span.end)
                    continue
                }
            }
            merged.append(span)
        }

        var result = merged.map { TimeSpan(start: $0.start, end: $0.end, isActive: false) }
        if let active = activeStart {
            if let last = merged.last {
                let gap = active.timeIntervalSince(last.end)
                if gap < mergeThreshold || gapCoveredByWork(gapEnd: active) {
                    result[result.count - 1] = TimeSpan(start: last.start, end: nil, isActive: true)
                } else {
                    result.append(TimeSpan(start: active, end: nil, isActive: true))
                }
            } else {
                result.append(TimeSpan(start: active, end: nil, isActive: true))
            }
        }
        return result
    }

    static func projectDurations(entries: [ProjectEntry], firstOnTime: Date?,
                                  spanStart: Date, spanEnd: Date) -> [ProjectDuration] {
        guard !entries.isEmpty else { return [] }
        let dayStart = firstOnTime ?? entries[0].time
        var durations: [String: TimeInterval] = [:]
        for i in 0..<entries.count {
            let entry = entries[i]
            let claimStart = i == 0 ? dayStart : entries[i - 1].time
            let intStart = max(claimStart, spanStart)
            let intEnd   = min(entry.time, spanEnd)
            if intEnd > intStart { durations[entry.project, default: 0] += intEnd.timeIntervalSince(intStart) }
        }
        if let last = entries.last {
            let intStart = max(last.time, spanStart)
            if spanEnd > intStart { durations[last.project, default: 0] += spanEnd.timeIntervalSince(intStart) }
        }
        return durations.map { ProjectDuration(project: $0.key, duration: $0.value) }
            .filter { $0.duration >= 30 }
            .sorted { $0.duration > $1.duration }
    }

    static func workedTime(spans: [TimeSpan], entries: [ProjectEntry],
                            firstOnTime: Date?, now: Date) -> TimeInterval {
        spans.reduce(0.0) { total, span in
            let spanEnd = span.end ?? now
            let d = projectDurations(entries: entries, firstOnTime: firstOnTime, spanStart: span.start, spanEnd: spanEnd)
            let breakDur = d.first(where: { $0.project == "Break" })?.duration ?? 0
            return total + max(0, spanEnd.timeIntervalSince(span.start) - breakDur)
        }
    }

    static func dailyProjectTotals(spans: [TimeSpan], entries: [ProjectEntry],
                                    firstOnTime: Date?, now: Date) -> [ProjectDuration] {
        var totals: [String: TimeInterval] = [:]
        for span in spans {
            let spanEnd = span.end ?? now
            for d in projectDurations(entries: entries, firstOnTime: firstOnTime, spanStart: span.start, spanEnd: spanEnd)
            where d.project != "Break" {
                totals[d.project, default: 0] += d.duration
            }
        }
        return totals.map { ProjectDuration(project: $0.key, duration: $0.value) }.sorted { $0.duration > $1.duration }
    }
}

// ---- CSV Parser ----

func parseCSV(_ csv: String, timeZone: TimeZone) -> (screenEvents: [ScreenEvent], projectEntries: [ProjectEntry]) {
    let fmt = DateFormatter()
    fmt.dateFormat = "yyyy-MM-dd HH:mm:ss"
    fmt.timeZone = timeZone
    var screenEvents: [ScreenEvent] = []
    var projectEntries: [ProjectEntry] = []

    func parseFields(_ line: String) -> [String] {
        var fields: [String] = []
        var current = ""
        var inQuotes = false
        var i = line.startIndex
        while i < line.endIndex {
            let c = line[i]
            if inQuotes {
                if c == "\"" {
                    let next = line.index(after: i)
                    if next < line.endIndex && line[next] == "\"" { current.append("\""); i = line.index(after: next); continue }
                    else { inQuotes = false }
                } else { current.append(c) }
            } else {
                if c == "\"" { inQuotes = true }
                else if c == "," { fields.append(current); current = "" }
                else { current.append(c) }
            }
            i = line.index(after: i)
        }
        fields.append(current)
        return fields
    }

    for line in csv.components(separatedBy: .newlines).dropFirst() {
        let f = parseFields(line)
        guard f.count >= 5 else { continue }
        guard let date = fmt.date(from: "\(f[0]) \(f[1])") else { continue }
        switch f[2] {
        case "on":           screenEvents.append(ScreenEvent(kind: .on, time: date))
        case "off":          screenEvents.append(ScreenEvent(kind: .off, time: date))
        case "screensaverOn":  screenEvents.append(ScreenEvent(kind: .screensaverOn, time: date))
        case "screensaverOff": screenEvents.append(ScreenEvent(kind: .screensaverOff, time: date))
        case "entry":        projectEntries.append(ProjectEntry(project: f[4], time: date))
        default: break
        }
    }
    screenEvents.sort { $0.time < $1.time }
    projectEntries.sort { $0.time < $1.time }
    return (screenEvents, projectEntries)
}

// ---- Load and analyze ----

let csvURL = URL(fileURLWithPath: "/Users/srdkvr/Library/Application Support/BarTimeTracker/events.csv")
guard let csvString = try? String(contentsOf: csvURL) else { print("Cannot read CSV"); exit(1) }

