// Gather unique workdays (days with user entries)
let workDays = Array(Set(allProjectEntries.map { startOfDay($0.time) })).sorted()

for day in workDays {
    let dayStr = fmt.string(from: day)
    let nextDay = cal.date(byAdding: .day, value: 1, to: day)!

    let dayScreenEvents = allScreenEvents.filter { $0.time >= day && $0.time < nextDay }
    let dayEntries = allProjectEntries.filter { $0.time >= day && $0.time < nextDay && !$0.project.hasPrefix("~") }

    // 'now' = last screen event of that day + 1s (or last entry + 1s)
    let lastEvent = dayScreenEvents.last?.time ?? dayEntries.last?.time ?? day
    let now = lastEvent.addingTimeInterval(1)

    let firstOnTime = dayScreenEvents.first(where: { $0.kind == .on || $0.kind == .screensaverOff })?.time
    let spans = TimeCalculations.buildTimeSpans(from: dayScreenEvents, projectEntries: dayEntries, now: now)
    let worked = TimeCalculations.workedTime(spans: spans, entries: dayEntries, firstOnTime: firstOnTime, now: now)
    let totals = TimeCalculations.dailyProjectTotals(spans: spans, entries: dayEntries, firstOnTime: firstOnTime, now: now)

